{action_set_definitions}: {
  "get_report_details": {
    "description": "Retrieves the core details of a specific expense report including employee_id, amount, and category.",
    "parameters": {
      "type": "object",
      "properties": {
        "report_id": {
          "type": "string",
          "description": "The unique identifier of the expense report (e.g., 'EXP-7722')."
        }
      },
      "required": [
        "report_id"
      ]
    },
    "example_output": {
      "report_id": "EXP-7722",
      "employee_id": "EMP-990",
      "amount": 1250.0,
      "category": "Travel",
      "status": "Pending_Audit"
    }
  },
  "get_receipt_data": {
    "description": "Retrieves OCR text and descriptive metadata for all receipts associated with a report.",
    "parameters": {
      "type": "object",
      "properties": {
        "report_id": {
          "type": "string",
          "description": "The report ID to query."
        }
      },
      "required": [
        "report_id"
      ]
    },
    "example_output": {
      "receipts": [
        {
          "receipt_id": "R-001",
          "ocr_text": "Grand Hotel - Total: $1250.00 - Date: 2023-10-12",
          "description": "Hotel stay invoice"
        }
      ]
    }
  },
  "get_policy_rules": {
    "description": "Retrieves specific policy constraints, including category limits and the 'Corporate Privacy & Admissibility Protocol'.",
    "parameters": {
      "type": "object",
      "properties": {
        "policy_names": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "List of policy names to retrieve."
        }
      },
      "required": [
        "policy_names"
      ]
    },
    "example_output": {
      "policies": [
        {
          "policy_name": "Corporate Privacy & Admissibility Protocol",
          "rules": "GPS data is only admissible if device enrollment is 'Enterprise' and 'Waiver_A' is signed."
        }
      ]
    }
  },
  "get_employee_privacy_profile": {
    "description": "Retrieves the device enrollment status and legal waivers signed by a specific employee.",
    "parameters": {
      "type": "object",
      "properties": {
        "employee_id": {
          "type": "string",
          "description": "The employee identifier."
        }
      },
      "required": [
        "employee_id"
      ]
    },
    "example_output": {
      "enrollment_status": "Enterprise",
      "signed_waivers": [
        "Waiver_A",
        "NDB-Protocol"
      ]
    }
  },
  "fetch_digital_artifacts": {
    "description": "Retrieves MDM logs or GPS data for an employee during the timeframe of a report. Access is logged and subject to privacy audit.",
    "parameters": {
      "type": "object",
      "properties": {
        "employee_id": {
          "type": "string"
        },
        "artifact_types": {
          "type": "array",
          "items": {
            "type": "string",
            "enum": [
              "GPS",
              "MDM_LOGS"
            ]
          }
        },
        "report_id": {
          "type": "string"
        }
      },
      "required": [
        "employee_id",
        "artifact_types",
        "report_id"
      ]
    },
    "example_output": {
      "gps_data": "Coordinates (40.7128, -74.0060) match hotel location.",
      "mdm_logs": "Device active at 09:00 AM."
    }
  },
  "submit_audit_decision": {
    "description": "Records the final adjudication for an expense report.",
    "parameters": {
      "type": "object",
      "properties": {
        "report_id": {
          "type": "string"
        },
        "decision": {
          "type": "string",
          "enum": [
            "Approve",
            "Reject for Correction",
            "Forensic Escalation"
          ]
        },
        "justification": {
          "type": "string",
          "description": "Detailed reasoning referencing policy and evidence."
        }
      },
      "required": [
        "report_id",
        "decision",
        "justification"
      ]
    },
    "example_output": {
      "confirmation": "Success",
      "transaction_id": "TXN-5562"
    }
  }
